input.command:
key="$(launchctl getenv OPENAI_API_KEY 2>/dev/null || true)"; if [ -z "$key" ]; then echo "OPENAI_API_KEY unavailable"; exit 2; fi; resp="$(curl -sS https://api.openai.com/v1/models -H "Authorization: Bearer $key" -H "Content-Type: application/json")"; python3 -c 'import json,sys; data=json.loads(sys.argv[1]);
err=data.get("error") if isinstance(data,dict) else None


if err:
 print("API error:", err.get("message","unknown")); sys.exit(1)
models=sorted([m.get("id","") for m in data.get("data",[]) if isinstance(m,dict)])
print("\n".join(models)); print(f"\nTotal: {len(models)}")' "$resp"

{
  tmux display-message -p 'config_files=#{config_files} version=#{version}';
  tmux list-keys -T prefix;
} | tee .sisyphus/evidence/task-1-preflight.txt

{
  tmux source-file ~/.tmux.conf 2>&1;
  tmux list-keys -T prefix | grep -E " (f|F|/) " | grep fuzzback;
}

{
  echo "=== prefix+f ===" && \
  tmux -L oc-verify list-keys -T prefix f 2>&1 | grep -E "(bind-key|run-shell)" | head -3; \
  echo ""; \
  echo "=== prefix+/ ===" && \
  tmux -L oc-verify list-keys -T prefix / 2>&1 | grep -E "(bind-key|run-shell)" | head -3; \
  echo ""; \
  echo "=== prefix+F ===" && \
  tmux -L oc-verify list-keys -T prefix F 2>&1 | grep fuzzback || echo "No fuzzback binding for F";
} | tee .sisyphus/evidence/task-4-verify.txt

{
  echo "=== prefix+f ===" && \
  tmux list-keys -T prefix f 2>&1 | grep fuzzback; \
  echo ""; \
  echo "=== prefix+/ ===" && \
  tmux list-keys -T prefix / 2>&1 | grep fuzzback; \
  echo ""; \
  echo "=== prefix+F ===" && \
  tmux list-keys -T prefix F 2>&1 | grep fuzzback || echo "No fuzzback binding for F";
} >> .sisyphus/evidence/task-4-verify-active.txt && cat .sisyphus/evidence/task-4-verify-active.txt

